import java.util.HashMap;
    import java.util.Map;
    import sailpoint.object.Link;
    import sailpoint.object.Identity;
    import sailpoint.object.Filter;
    import sailpoint.object.QueryOptions;
    import org.apache.log4j.Logger;
    import org.apache.log4j.Level;
    import sailpoint.tools.Util;

 

    Map returnMap = new HashMap();
    boolean found = false;
    String upn = (String) account.getAttribute("userPrincipalName");
    String immutableId = (String) account.getAttribute("immutableId");
	
	
	     static String azurePSOutput;  //psReader(String command) method sets this variable

  public void psReader(String command){

    import java.io.BufferedReader;
    import java.io.IOException;
    import java.io.InputStreamReader;

    try{

      java.lang.Process proc = Runtime.getRuntime().exec(command);

      proc.getOutputStream().close();

      String line;

      BufferedReader stdout = new BufferedReader(new InputStreamReader(proc.getInputStream()));

      while ((line = stdout.readLine()) != null) {

        azurePSOutput = line;

      }

      stdout.close();

    } catch (Exception ex) {

      "Error:" + ex;

    }

  }

  private String immuteIDtoGuid(String immuteID){ //runs ppowershell script to convert immuteID to ObjectGuid from Azure

    String command = "powershell.exe D:/IQScripts/AzuretoADCoor.ps1" + " " + immuteID;

    psReader(command);

    return azurePSOutput;

  }
	
	
    String objectGuid = "{" + ((String) immuteIDtoGuid(immutableId)) + "}";


    if (!found){

        if(!found){  //Matching Objectguid from Azure to ConsistencyGuid from AD
		
  Filter f = Filter.and(
    Filter.eq("consistencyGuid", objectGuid),
    Filter.eq("application.type", "Active Directory - Direct")
    );
  
  					Link matchingLink = context.getUniqueObject(Link.class, f);
            if (matchingLink != null) {
			found = true;
			String identityName = matchingLink.getIdentity().getName();
			returnMap.put("identityName", identityName);
			}
  }
            }
            if(!found) { //if fails attempt to match objectguid to objecguid and UPN to email
			QueryOptions qo = new QueryOptions();
			  qo.addFilter(Filter.and(
    Filter.eq("objectGuid", objectGuid),
    Filter.eq("application.type", "Active Directory - Direct")
    ));
	List matchingLinks = context.getObjects(Link.class, qo);
  for (Link link: matchingLinks){
    
  
            if (link != null) {
			
			Identity identity = link.getIdentity();
              
              if (Util.nullSafeCaseInsensitiveEq(identity.getEmail(), upn))
              {
                
                found = true;
			String identityName = link.getIdentity().getName();
			returnMap.put("identityName", identityName);
               break; 
            } 
	
            }
        }
    }
	
	        if(!found){ //falls back to UPN to email only as a last resort for correlation
		
			QueryOptions qo = new QueryOptions();
			  qo.addFilter(Filter.ignoreCase(Filter.eq("email",upn)));
	List matchingIdentity = context.getObjects(Identity.class, qo);
  for (Identity identity: matchingIdentity){
    
  
            if (identity != null) {

			String identityName = identity.getName();
			returnMap.put("identityName", identityName);
               break; 
            }
        }
  }
    
    return returnMap;
